### Exhaustiveness Checking

Exhaustiveness checking ensures every variant of a union type is handled. Use the never type pattern: assign unhandled cases to a variable of type `never`, forcing a compile-time error if any case is missing.

This technique works because if all union members are handled, the remaining type is `never`. If a new union member is added later, TypeScript will catch the missing handler immediately.

```typescript
type Status = 'pending' | 'success' | 'error';

function handleStatus(status: Status): string {
  switch (status) {
    case 'pending':
      return 'Waiting...';
    case 'success':
      return 'Done!';
    case 'error':
      return 'Failed!'
    default:
      const _exhaustive: never = status;
      return _exhaustive;
  }
}

type Result<T> = { type: 'ok'; data: T } | { type: 'err'; error: string };

function processResult<T>(r: Result<T>) {
  switch (r.type) {
    case 'ok': return r.data;
    case 'err': return null;
    default:
      const _: never = r;
  }
}
```


**Common interview trap:** Candidates forget the `default` branch—without it, new union members won't trigger compilation errors because they fall through silently.

