class UserBuilder<Done extends keyof User = never> {
  private data: Partial<User> = {};

  setName(name: string): UserBuilder<Done | 'name'> {
    this.data.name = name;
    return this as any;
  }

  setEmail(email: string): UserBuilder<Done | 'email'> {
    this.data.email = email;
    return this as any;
  }

  setAge(age: number): UserBuilder<Done | 'age'> {
    this.data.age = age;
    return this as any;
  }

  // build() доступен только когда Done включает ВСЕ ключи User
  build(this: UserBuilder<keyof User>): User {
    return this.data as User;
  }
}

// ✓ Все обязательные поля установлены — build() доступен
const user = new UserBuilder()
  .setName('Alice')
  .setEmail('alice@example.com')
  .setAge(30)
  .build();

// ✗ Пропущен .setAge() — ошибка TypeScript на .build():
// "The 'this' context of type UserBuilder<'name' | 'email'> is not assignable
//  to method's 'this' of type UserBuilder<keyof User>"
const incomplete = new UserBuilder().setName('Bob').setEmail('b@b.com').build();
```

Сигнатура `build(this: UserBuilder<keyof User>)` использует типизированный параметр `this` для гарантии того, что `Done` равен `keyof User` перед вызовом.

**Типичная ошибка на интервью:** Использование `Set extends keyof T` как условие для `build()` — это всегда `true`, поскольку `Set` ограничен `keyof T`. Правильная проверка обратная: `[keyof T] extends [Set]` (обёрнутая в `[]` для предотвращения дистрибутивности), которая истинна только когда все ключи `T` содержатся в `Set`.

